import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type DocType = 'NE' | 'FISCAL_INVOICE' | 'QUOTATION' | 'ORDER';

export interface Company {
  id: string;
  name: string;
  rif: string;
}

export interface Branch {
  id: string;
  name: string;
  code: string;
}

export interface Warehouse {
  id: string;
  name: string;
  type: 'TIENDA' | 'DEPOSITO';
  branchId: string;
}

export interface Product {
  id: string;
  sku: string;
  description: string;
  brand: string;
  unit: string;
  stock: number; // Consolidated
  minStock: number;
}

export interface Supplier {
  id: string;
  name: string;
  rif: string;
  leadTimeDays: number;
  deliveryAccuracy: number; // Percentage
  historicalOnTime?: number;
}

export interface InventoryMovement {
  id: string;
  productId: string;
  warehouseId: string;
  type: 'IN' | 'OUT' | 'TRANSFER';
  quantity: number;
  date: string;
  reason: string;
}

export interface PurchaseOrder {
  id: string;
  supplierId: string;
  supplierName: string;
  date: string;
  expectedDate: string;
  total: number;
  status: 'PENDING' | 'RECEIVED' | 'CANCELLED';
}

export interface SyncLog {
  id: string;
  eventType: string;
  payload: any;
  status: 'PENDING' | 'SENT' | 'ERROR';
  lastError?: string;
  createdAt: string;
}

