          )}
          <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-1 hover:bg-gray-800 rounded">
            {isSidebarOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
        </div>

        <nav className="flex-1 px-3 space-y-1 overflow-y-auto">
          <NavItem icon={LayoutDashboard} label="Dashboard" view="dashboard" />
          <NavItem icon={Package} label="Inventario" view="inventory" />
          <NavItem icon={Truck} label="Proveedores" view="suppliers" />
          <NavItem icon={ShoppingCart} label="Ventas (NE)" view="sales" />
          <NavItem icon={ArrowLeftRight} label="Compras" view="purchases" />
          <div className="pt-4 pb-2 border-t border-gray-800 mt-4">
            {isSidebarOpen && <span className="px-4 text-[10px] text-gray-500 uppercase font-bold">Integración SAINT</span>}
