            <div className="w-8 h-8 rounded-full bg-ferrari-red flex items-center justify-center font-bold text-xs">AD</div>
            {isSidebarOpen && (
              <div className="flex flex-col">
                <span className="text-sm font-semibold">Admin RG7</span>
                <span className="text-[10px] text-gray-500">Sucursal Principal</span>
              </div>
            )}
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto relative">
        <header className="bg-white border-b sticky top-0 z-10 px-8 py-4 flex items-center justify-between">
          <h1 className="text-xl font-bold text-gray-800 capitalize">{activeView}</h1>
          <div className="flex items-center space-x-4">
            <div className="flex items-center space-x-2 bg-green-50 px-3 py-1 rounded-full border border-green-100">
              <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
              <span className="text-[10px] font-bold text-green-700 uppercase">Saint Online</span>
            </div>
            <button className="p-2 text-gray-400 hover:text-gray-600">
              <Database size={20} />
            </button>
          </div>
        </header>

        <div className="p-8">
          {activeView === 'dashboard' && <Dashboard />}
          {activeView === 'inventory' && <Inventory />}
          {activeView === 'suppliers' && <Suppliers />}
          {activeView === 'sales' && <SalesNE />}
          {activeView === 'purchases' && <Purchases />}
          {activeView === 'sync' && <SyncLogs />}
          {activeView === 'settings' && (
            <div className="bg-white p-6 rounded-xl shadow-sm border">
              <h2 className="text-lg font-bold mb-4">Módulo en construcción</h2>
              <p className="text-gray-500 text-sm">El configurador de parámetros fiscales y multi-empresa estará disponible en la v1.2</p>
            </div>
          )}
