import React, { useState } from 'react';
import { mockProducts, mockWarehouses } from '../services/mockData';
import { Search, Filter, Warehouse as WarehouseIcon, Package, ArrowRightLeft } from 'lucide-react';

export const Inventory: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedWarehouse, setSelectedWarehouse] = useState('all');

  const filteredProducts = mockProducts.filter(p => 
    p.description.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.sku.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      {/* Toolbar */}
      <div className="flex flex-col md:flex-row md:items-center gap-4 bg-white p-4 rounded-xl shadow-sm border">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
          <input 
            type="text" 
            placeholder="Buscar por SKU, descripción o marca..." 
            className="w-full pl-10 pr-4 py-2 bg-gray-50 border rounded-lg focus:outline-none focus:ring-2 focus:ring-ferrari-red/20 focus:border-ferrari-red"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex items-center gap-2">
          <Filter className="text-gray-400" size={18} />
          <select 
            className="bg-gray-50 border rounded-lg px-3 py-2 text-sm focus:outline-none"
            value={selectedWarehouse}
            onChange={(e) => setSelectedWarehouse(e.target.value)}
          >
            <option value="all">Todos los Almacenes</option>
            {mockWarehouses.map(w => (
              <option key={w.id} value={w.id}>{w.name}</option>
            ))}
          </select>
        </div>
        <button className="bg-ferrari-red text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-red-700 transition-colors">
          <ArrowRightLeft size={18} />
          Trasladar Mercancía
        </button>
      </div>

      {/* Grid */}
      <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
        <table className="w-full text-sm">
          <thead className="bg-gray-100 text-gray-600 uppercase text-[10px] font-bold">
            <tr>
              <th className="px-6 py-4 text-left">SKU / Marca</th>
              <th className="px-6 py-4 text-left">Descripción</th>
              <th className="px-6 py-4 text-center">Tienda</th>
              <th className="px-6 py-4 text-center">Depósito</th>
              <th className="px-6 py-4 text-right">Total</th>
              <th className="px-6 py-4 text-center">Estatus</th>
            </tr>
          </thead>
          <tbody className="divide-y">
            {filteredProducts.map(p => (
              <tr key={p.id} className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4">
                  <div className="flex flex-col">
                    <span className="font-mono font-bold text-ferrari-red">{p.sku}</span>
                    <span className="text-[10px] text-gray-400 uppercase font-bold">{p.brand}</span>
                  </div>
                </td>
                <td className="px-6 py-4 font-medium">{p.description}</td>
                <td className="px-6 py-4 text-center font-mono">{Math.floor(p.stock * 0.3)}</td>
                <td className="px-6 py-4 text-center font-mono">{Math.ceil(p.stock * 0.7)}</td>
                <td className="px-6 py-4 text-right font-bold text-lg">{p.stock}</td>
                <td className="px-6 py-4 text-center">
                  <span className={`px-2 py-1 rounded-full text-[10px] font-bold uppercase ${
