                  }`}>
                    {p.stock >= p.minStock ? 'Óptimo' : p.stock > 0 ? 'Crítico' : 'Agotado'}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

